const express = require('express');
const app = express();
const http = require('http').createServer(app);
const io = require('socket.io')(http);
const { v4: uuidv4 } = require('uuid');

// Initialize the game state
let gameState = {
  players: {},
  scores: {}
};

// Handle incoming connections
io.on('connection', (socket) => {
  console.log(`New client connected: ${socket.id}`);

  // Handle player authentication
  socket.on('authenticate', (username, password) => {
    if (username && password) {
      const player = gameState.players[username];
      if (player && player.password === password) {
        console.log(`Player ${username} authenticated`);
        socket.join(username);
        socket.emit('authenticated', true);
      } else {
        console.log(`Invalid authentication attempt for player ${username}`);
        socket.emit('authenticated', false);
      }
    } else {
      console.log(`Player ${username} failed to authenticate`);
      socket.emit('authenticated', false);
    }
  });

  // Handle player moves
  socket.on('move', (move) => {
    if (move && move.x && move.y) {
      const player = gameState.players[socket.id];
      if (player) {
        console.log(`Player ${player.username} made a move`);
        // Validate the move on the client-side and trust the reported score
        socket.emit('move', move);
      } else {
        console.log(`Invalid move received from player ${socket.id}`);
      }
    } else {
      console.log(`Player ${socket.id} failed to make a move`);
    }
  });

  // Handle score updates
  socket.on('score', (score) => {
    if (score && score.username && score.score) {
      const player = gameState.players[score.username];
      if (player) {
        console.log(`Player ${player.username} updated their score`);
        // Update the player's score in the game state
        player.score = score.score;
        // Emit the new score to all connected clients
        io.emit('score', { username: player.username, score: player.score });
      } else {
        console.log(`Invalid score update received from player ${socket.id}`);
      }
    } else {
      console.log(`Player ${socket.id} failed to update their score`);
    }
  });

  // Handle disconnections
  socket.on('disconnect', () => {
    const player = gameState.players[socket.id];
    if (player) {
      console.log(`Player ${player.username} disconnected`);
      delete gameState.players[socket.id];
      // Emit the updated list of players to all connected clients
      io.emit('players', Object.keys(gameState.players));
    } else {
      console.log(`Player ${socket.id} failed to disconnect`);
    }
  });
});

// Start the server
http.listen(3000, () => {
  console.log('Server started on port 3000');
});